if SLIDESHOW_IMAGES:
    images_js = '[' + ','.join(f'"{img}"' for img in SLIDESHOW_IMAGES) + ']'
    bg_html = f"""
<div class="stadium-bg" id="stadium-bg-container">
  <div id="slide-a" style="position:absolute;inset:0;background-size:cover;background-position:center;transition:opacity 1.6s ease;"></div>
  <div id="slide-b" style="position:absolute;inset:0;background-size:cover;background-position:center;opacity:0;transition:opacity 1.6s ease;"></div>
</div>
<div class="scroll-overlay"></div>
<script>
(function(){{
  var images = {images_js};
  var INTERVAL = 5000;
  var slideA = document.getElementById('slide-a');
  var slideB = document.getElementById('slide-b');
  if (!slideA || images.length === 0) return;
  var current = 0, showingA = true;
  slideA.style.backgroundImage = 'url(' + images[0] + ')';
  slideA.style.opacity = '1';
  setInterval(function() {{
    var next = (current + 1) % images.length;
    var inc = showingA ? slideB : slideA;
    var out = showingA ? slideA : slideB;
    inc.style.backgroundImage = 'url(' + images[next] + ')';
    inc.style.opacity = '1';
    out.style.opacity = '0';
    showingA = !showingA;
    current = next;
  }}, INTERVAL);
}})();

function switchMatch(mk) {{
  document.querySelectorAll('.match-tab').forEach(function(t) {{ t.classList.remove('active'); }});
  document.querySelectorAll('.match-btn').forEach(function(b) {{ b.classList.remove('active'); }});
  var el = document.getElementById('match-' + mk);
  if (el) el.classList.add('active');
  document.querySelectorAll('.match-btn').forEach(function(b) {{
    if (b.getAttribute('onclick').indexOf(mk) > -1) b.classList.add('active');
  }});
}}
function switchRoster(owner) {{
  document.querySelectorAll('.roster-tab').forEach(function(t) {{ t.classList.remove('active'); }});
  document.querySelectorAll('.roster-btn').forEach(function(b) {{ b.classList.remove('active'); }});
  var el = document.getElementById('roster-' + owner);
  if (el) el.classList.add('active');
  document.querySelectorAll('.roster-btn').forEach(function(b) {{
    if (b.getAttribute('onclick').indexOf(owner) > -1) b.classList.add('active');
  }});
}}
</script>"""
